func (_q *ChurchQuery) loadParent(ctx context.Context, query *ChurchQuery, nodes []*Church, init func(*Church), assign func(*Church, *Church)) error {
	ids := make([]int, 0, len(nodes))
	nodeids := make(map[int][]*Church)
	for i := range nodes {
		fk := nodes[i].ParentID
		if _, ok := nodeids[fk]; !ok {
			ids = append(ids, fk)
		}
		nodeids[fk] = append(nodeids[fk], nodes[i])
	}
	if len(ids) == 0 {
		return nil
	}
	query.Where(church.IDIn(ids...))
	neighbors, err := query.All(ctx)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		nodes, ok := nodeids[n.ID]
		if !ok {
			return fmt.Errorf(`unexpected foreign-key "parent_id" returned %v`, n.ID)
		}
		for i := range nodes {
			assign(nodes[i], n)
		}
	}
	return nil
}
func (_q *ChurchQuery) loadChildren(ctx context.Context, query *ChurchQuery, nodes []*Church, init func(*Church), assign func(*Church, *Church)) error {
	fks := make([]driver.Value, 0, len(nodes))
	nodeids := make(map[int]*Church)
	for i := range nodes {
		fks = append(fks, nodes[i].ID)
		nodeids[nodes[i].ID] = nodes[i]
		if init != nil {
			init(nodes[i])
		}
	}
	if len(query.ctx.Fields) > 0 {
		query.ctx.AppendFieldOnce(church.FieldParentID)
	}
	query.Where(predicate.Church(func(s *sql.Selector) {
		s.Where(sql.InValues(s.C(church.ChildrenColumn), fks...))
	}))
	neighbors, err := query.All(ctx)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		fk := n.ParentID
		node, ok := nodeids[fk]
		if !ok {
			return fmt.Errorf(`unexpected referenced foreign-key "parent_id" returned %v for node %v`, fk, n.ID)
		}
		assign(node, n)
	}
	return nil
}
